oxy_webhelp_navlinks = {"tocId-d30753e52585":{"topics":[{"title":"Integration of third-party applications in <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\">You can access the Integrations page to configure and manage your third-party SaaS         integrations in <span class=\"ph\">RSC<\/span>.<\/p>","href":"saas\/integration_third_party_apps_in_rsc.html","attributes":{"data-id":"integration_third_party_apps_in_rsc"},"menu":{"hasChildren":true},"tocID":"integration_third_party_apps_in_rsc-d30753e52591","next":"integration_third_party_apps_in_rsc-d30753e52591"},{"title":"Licenses and usage details","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides a view of license and usage details for workloads. The         Licenses and Usage page helps you analyze the current data protection usage and make         informed decisions about future license requirements, based on various combinations of the         number of users, storage capacity, and workload.<\/p>","href":"saas\/licenses_usage_details.html","attributes":{"data-id":"licenses_usage_details"},"menu":{"hasChildren":true},"tocID":"licenses_usage_details-d30753e53143","next":"licenses_usage_details-d30753e53143"}]}};